package com.example.samlsp.controller;

import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import java.security.Principal;
import java.util.Collections;
import java.util.Enumeration;
import java.util.LinkedHashMap;
import java.util.Map;
import org.springframework.http.MediaType;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

@RestController
public class HomeController {

    @GetMapping(value = "/", produces = MediaType.TEXT_PLAIN_VALUE)
    public String home(Principal principal, HttpServletRequest request) {
        if (principal == null) {
            return "Unauthenticated. POST SAMLResponse to /saml/acs";
        }
        HttpSession session = request.getSession(false);
        Map<String, Object> attrs = new LinkedHashMap<>();
        if (session != null) {
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                attrs.put(name, session.getAttribute(name));
            }
        }
        return "Authenticated as: " + principal.getName() + " sessionAttributes=" + attrs;
    }

    @GetMapping(value = "/me", produces = MediaType.APPLICATION_JSON_VALUE)
    public Map<String, Object> me(Principal principal, HttpServletRequest request) {
        if (principal == null) {
            return Collections.singletonMap("authenticated", false);
        }
        Map<String, Object> result = new LinkedHashMap<>();
        result.put("authenticated", true);
        result.put("name", principal.getName());
        HttpSession session = request.getSession(false);
        Map<String, Object> attrs = new LinkedHashMap<>();
        if (session != null) {
            Enumeration<String> names = session.getAttributeNames();
            while (names.hasMoreElements()) {
                String name = names.nextElement();
                attrs.put(name, session.getAttribute(name));
            }
        }
        result.put("sessionAttributes", attrs);
        return result;
    }
}

