package com.example.samlsp.security;

import com.example.samlsp.service.SamlResponseParser;
import com.example.samlsp.service.SamlUserDetails;
import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import java.io.IOException;
import java.util.Collection;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;
import org.springframework.http.HttpMethod;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

@Component
public class SamlAuthenticationFilter extends OncePerRequestFilter {

    private final SamlResponseParser samlResponseParser;

    public SamlAuthenticationFilter(SamlResponseParser samlResponseParser) {
        this.samlResponseParser = samlResponseParser;
    }

    @Override
    protected boolean shouldNotFilter(HttpServletRequest request) {
        return !("/saml/acs".equals(request.getRequestURI()) && HttpMethod.POST.matches(request.getMethod()));
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
        throws ServletException, IOException {

        String samlResponse = request.getParameter("SAMLResponse");
        if (samlResponse == null || samlResponse.isBlank()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing SAMLResponse");
            return;
        }

        try {
            SamlUserDetails userDetails = samlResponseParser.parse(samlResponse);

            Collection<SimpleGrantedAuthority> authorities = extractAuthorities(userDetails.attributes());
            SamlAuthenticationToken authentication =
                new SamlAuthenticationToken(userDetails.nameId(), userDetails.attributes(), authorities);

            SecurityContextHolder.getContext().setAuthentication(authentication);

            HttpSession session = request.getSession(true);
            session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());
            session.setAttribute("saml.nameId", userDetails.nameId());
            for (Map.Entry<String, Object> entry : userDetails.attributes().entrySet()) {
                session.setAttribute("saml.attr." + entry.getKey(), entry.getValue());
            }

            response.sendRedirect("/");
        } catch (Exception e) {
            SecurityContextHolder.clearContext();
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Invalid SAMLResponse");
        }
    }

    private Collection<SimpleGrantedAuthority> extractAuthorities(Map<String, Object> attributes) {
        Object roles = attributes.get("roles");
        if (roles instanceof List<?> list) {
            return list.stream().map(String::valueOf).map(SimpleGrantedAuthority::new).collect(Collectors.toList());
        }
        Object groups = attributes.get("groups");
        if (groups instanceof List<?> list) {
            return list.stream().map(String::valueOf).map(SimpleGrantedAuthority::new).collect(Collectors.toList());
        }
        return List.of(new SimpleGrantedAuthority("ROLE_USER"));
    }
}

