package com.example.samlsp.service;

import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import javax.xml.XMLConstants;
import javax.xml.namespace.NamespaceContext;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import javax.xml.xpath.XPath;
import javax.xml.xpath.XPathConstants;
import javax.xml.xpath.XPathFactory;
import org.springframework.stereotype.Service;
import org.w3c.dom.Document;
import org.w3c.dom.Node;
import org.w3c.dom.NodeList;

@Service
public class SamlResponseParser {

    public SamlUserDetails parse(String base64SamlResponse) throws Exception {
        byte[] decoded = Base64.getDecoder().decode(base64SamlResponse);
        String xml = new String(decoded, StandardCharsets.UTF_8);

        Document document = parseXmlSecurely(xml);
        XPath xpath = buildXPath();

        String statusCode = xpath.evaluate("/samlp:Response/samlp:Status/samlp:StatusCode/@Value", document);
        if (statusCode == null || statusCode.isBlank() || !statusCode.endsWith(":Success") && !statusCode.equals("urn:oasis:names:tc:SAML:2.0:status:Success")) {
            throw new IllegalArgumentException("SAML status is not success");
        }

        String nameId = xpath.evaluate("string(//saml:Assertion/saml:Subject/saml:NameID)", document);
        if (nameId == null || nameId.isBlank()) {
            nameId = xpath.evaluate("string(//saml:Subject/saml:NameID)", document);
        }
        if (nameId == null || nameId.isBlank()) {
            throw new IllegalArgumentException("Missing NameID");
        }

        validateConditions(xpath, document);

        Map<String, Object> attributes = extractAttributes(xpath, document);
        attributes.putIfAbsent("nameId", nameId);

        return new SamlUserDetails(nameId, attributes);
    }

    private void validateConditions(XPath xpath, Document document) throws Exception {
        String notBefore = xpath.evaluate("string(//saml:Assertion/saml:Conditions/@NotBefore)", document);
        String notOnOrAfter = xpath.evaluate("string(//saml:Assertion/saml:Conditions/@NotOnOrAfter)", document);
        Instant now = Instant.now();

        if (notBefore != null && !notBefore.isBlank()) {
            Instant nb = Instant.parse(notBefore);
            if (now.isBefore(nb.minusSeconds(60))) {
                throw new IllegalArgumentException("Assertion not yet valid");
            }
        }
        if (notOnOrAfter != null && !notOnOrAfter.isBlank()) {
            Instant noa = Instant.parse(notOnOrAfter);
            if (!now.isBefore(noa.plusSeconds(60))) {
                throw new IllegalArgumentException("Assertion expired");
            }
        }
    }

    private Map<String, Object> extractAttributes(XPath xpath, Document document) throws Exception {
        Map<String, Object> attributes = new LinkedHashMap<>();
        NodeList attrNodes = (NodeList) xpath.evaluate("//saml:Assertion/saml:AttributeStatement/saml:Attribute", document, XPathConstants.NODESET);
        for (int i = 0; i < attrNodes.getLength(); i++) {
            Node attr = attrNodes.item(i);
            Node nameNode = attr.getAttributes().getNamedItem("Name");
            if (nameNode == null) {
                continue;
            }
            String name = nameNode.getNodeValue();
            NodeList values = (NodeList) xpath.evaluate("saml:AttributeValue", attr, XPathConstants.NODESET);
            List<String> collected = new ArrayList<>();
            for (int j = 0; j < values.getLength(); j++) {
                String value = values.item(j).getTextContent();
                if (value != null) {
                    collected.add(value.trim());
                }
            }
            if (collected.size() == 1) {
                attributes.put(name, collected.get(0));
            } else {
                attributes.put(name, collected);
            }
        }
        return attributes;
    }

    private Document parseXmlSecurely(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
        factory.setAttribute(XMLConstants.ACCESS_EXTERNAL_SCHEMA, "");
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        return builder.parse(new ByteArrayInputStream(xml.getBytes(StandardCharsets.UTF_8)));
    }

    private XPath buildXPath() {
        XPath xpath = XPathFactory.newInstance().newXPath();
        xpath.setNamespaceContext(new SamlNamespaceContext());
        return xpath;
    }

    private static class SamlNamespaceContext implements NamespaceContext {
        @Override
        public String getNamespaceURI(String prefix) {
            if ("samlp".equals(prefix)) {
                return "urn:oasis:names:tc:SAML:2.0:protocol";
            }
            if ("saml".equals(prefix)) {
                return "urn:oasis:names:tc:SAML:2.0:assertion";
            }
            return XMLConstants.NULL_NS_URI;
        }

        @Override
        public String getPrefix(String namespaceURI) {
            return null;
        }

        @Override
        public java.util.Iterator<String> getPrefixes(String namespaceURI) {
            return java.util.Collections.emptyIterator();
        }
    }
}